/**
 * 📜 CONTRACT EXECUTOR (V51 - FIDELIDADE ABSOLUTA)
 * -------------------------------------------------------
 * Este componente é o executor final do DNA aprendido no Laboratório.
 * GARANTIA: O que é visto na simulação é o que é gerado aqui.
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        const rawBase64 = adaptedInput?.__base64; 

        if (!rawText.trim() && !rawBase64) return [];

        const { mapping } = model;
        const modelKeywords = mapping.ignoredKeywords || [];

        // 🧱 MODO BLOCO (IA VISION)
        if (mapping.extractionMode === 'BLOCK') {
            const trainingContext = mapping.blockContract || 'Extração fiel conforme modelo estrutural.';

            try {
                const aiResult = await extractTransactionsWithModel(rawText, trainingContext, rawBase64);
                const rows = Array.isArray(aiResult) ? aiResult : (aiResult?.rows || []);

                return rows.map((tx: any, idx: number) => {
                    // VERDADE ÚNICA: Aplica a mesma limpeza do Laboratório no output da IA
                    const cleanedDesc = NameResolver.clean(String(tx.description || ""), modelKeywords, globalKeywords);

                    return {
                        id: `exec-v51-block-${model.id}-${idx}-${Date.now()}`,
                        date: tx.date || "",
                        description: cleanedDesc, 
                        rawDescription: tx.description || "",
                        amount: tx.amount || 0,
                        originalAmount: String(tx.amount || 0),
                        cleanedDescription: cleanedDesc,
                        contributionType: 'AUTO',
                        paymentMethod: tx.paymentMethod || 'OUTROS',
                        bank_id: model.id
                    };
                });
            } catch (e) { 
                console.error("[ContractExecutor] Erro na leitura IA:", e);
                return []; 
            }
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const delimiter = line.includes(';') ? ';' : (line.includes('\t') ? '\t' : ',');
            const cells = line.split(delimiter).map(c => c.trim());

            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";
            const rawForm = (mapping.paymentMethodColumnIndex !== undefined && mapping.paymentMethodColumnIndex >= 0) 
                ? cells[mapping.paymentMethodColumnIndex] 
                : "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                // VERDADE ÚNICA: A descrição da Lista Viva é limpa exatamente como na Simulação
                const cleanedName = NameResolver.clean(rawDesc, modelKeywords, globalKeywords);

                results.push({
                    id: `exec-v51-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: cleanedName, 
                    rawDescription: rawDesc,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedName,
                    contributionType: numAmount >= 0 ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: rawForm || 'OUTROS',
                    bank_id: model.id
                });
            }
        });

        return results;
    }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from "../types";
import { Logger } from "./monitoringService";
import { NameResolver } from "../core/processors/NameResolver";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("API Key missing");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const parseEmailBatch = async (emails: { id: string, snippet: string, body: string, date: string, subject: string }[]): Promise<Transaction[]> => {
    if (emails.length === 0) return [];

    try {
        const ai = getAIClient();
        const emailData = emails.map(e => `ID: ${e.id} | ASSUNTO: ${e.subject} | CORPO: ${e.body.substring(0, 500)}`).join('\n---\n');

        const prompt = `Extraia transações bancárias (Pix, Transferências) destes e-mails. Entradas positivas, Saídas negativas. Retorne JSON Array de objetos {id, date, description, amount, type}.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `${prompt}\n\n${emailData}`,
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            date: { type: Type.STRING },
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            type: { type: Type.STRING }
                        },
                        required: ["id", "date", "description", "amount"]
                    }
                }
            }
        });

        const extracted = response.text ? JSON.parse(response.text) : [];

        return extracted.map((item: any) => {
            const cleanedDesc = NameResolver.clean(item.description || "");
            return {
                id: `gmail-${item.id}`,
                date: item.date,
                description: cleanedDesc,
                rawDescription: `GMAIL: ${item.description}`,
                cleanedDescription: cleanedDesc, 
                amount: item.amount,
                originalAmount: String(item.amount),
                contributionType: item.type || 'PIX'
            };
        });

    } catch (error) {
        Logger.error("Erro ao parsear e-mails com IA", error);
        return [];
    }
};

/**
 * 🎯 FONTE ÚNICA DE VERDADE: INTELIGÊNCIA NOMINAL (V10 - RE-ATIVADA)
 * Esta classe é responsável por garantir a paridade absoluta entre a Simulação e a Lista Viva.
 */
export class NameResolver {

  static identifyNameColumn(rows: string[][], excludedIndices: number[] = []): number {
    const sample = rows.slice(0, 50);
    if (sample.length === 0) return -1;
    const scores = new Array(rows[0]?.length || 0).fill(0);
    sample.forEach(row => {
        row.forEach((cell, index) => {
            if (excludedIndices.includes(index)) return;
            const val = String(cell || '').trim();
            if (val.length > 4 && !/^[\d.,R$\s\-()]+$/.test(val)) {
                scores[index] += 1;
                if (val.split(' ').length > 1) scores[index] += 0.5;
            }
        });
    });
    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : -1;
  }

  /**
   * LIMPEZA DETERMINÍSTICA:
   * Remove as palavras-chave aprendidas do modelo e as globais do sistema.
   * Única fonte da 'Verdade' para a descrição secundária na Lista Viva.
   */
  static clean(rawName: string, modelKeywords: string[] = [], globalKeywords: string[] = []): string {
    if (!rawName) return '';

    let cleaned = rawName.toUpperCase();

    // 1. Sanitização física
    cleaned = cleaned
        .replace(/[\t\r\n]/g, ' ') 
        .replace(/\s+/g, ' ')      
        .trim();

    // 2. Remoção de Palavras Ignoradas (O "Aprendizado")
    // Combina keywords do modelo e globais, removendo duplicatas
    const allKeywords = Array.from(new Set([
        ...modelKeywords.map(k => k.toUpperCase()),
        ...globalKeywords.map(k => k.toUpperCase())
    ])).filter(k => k.length > 0);

    // Ordena por tamanho descendente para remover termos mais específicos primeiro
    allKeywords.sort((a, b) => b.length - a.length);

    allKeywords.forEach(keyword => {
        if (!keyword) return;
        // Escapa caracteres especiais para Regex e garante match de palavra inteira ou prefixo
        const escapedKeyword = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(`\\b${escapedKeyword}\\b|${escapedKeyword}\\s+`, 'g');
        cleaned = cleaned.replace(regex, ' ');
    });

    // 3. Limpeza final de espaços
    return cleaned.replace(/\s+/g, ' ').trim() || rawName.toUpperCase().trim();
  }

  static formatDisplayName(name: string): string {
    return name || '';
  }

  static normalize(text: string): string {
    if (!text) return '';
    return text
      .toUpperCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '') 
      .replace(/\s+/g, ' ')           
      .trim();
  }
}

